wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(81115566386384537)
,p_plug_name=>unistr('Terminarz Spotka\0144')
,p_title=>unistr('Terminarz Spotka\0144')
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>40
,p_plug_grid_column_span=>10
,p_plug_display_column=>2
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    m.match_id,',
'    ''Runda '' || (FLOOR((TRUNC(m.match_date) - TO_DATE(''2024-07-19'', ''YYYY-MM-DD'')) / 7) + 1) as ROUND_NO,',
'    m.match_date as DATA_MECZU,',
'    th.name as GOSPODARZ,',
'    m.score_home || '':'' || m.score_away as WYNIK,',
'    ta.name as GOSC,',
'    s.name as STADIUM',
'FROM Match m',
'JOIN Team th ON m.home_team_id = th.club_id',
'JOIN Team ta ON m.away_team_id = ta.club_id',
'JOIN Stadium s ON m.stadium_id = s.stadium_id',
'WHERE (',
'    :P18_ROUND IS NULL ',
'    OR FLOOR((TRUNC(m.match_date) - TO_DATE(''2024-07-19'', ''YYYY-MM-DD'')) / 7) + 1 = :P18_ROUND',
