,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select "CLUB_ID",',
'    null LINK_CLASS,',
'    apex_page.get_url(p_items => ''P34_CLUB_ID'', p_values => "CLUB_ID") LINK,',
'    null ICON_CLASS,',
'    null LINK_ATTR,',
'    null ICON_COLOR_CLASS,',
'    case when coalesce(:P34_CLUB_ID,''0'') = "CLUB_ID"',
'      then ''is-active'' ',
'      else '' ''',
'    end LIST_CLASS,',
'    (substr("NAME", 1, 50)||( case when length("NAME") > 50 then ''...'' else '''' end )) LIST_TITLE,',
'    (substr("CITY", 1, 50)||( case when length("CITY") > 50 then ''...'' else '''' end )) LIST_TEXT,',
'    null LIST_BADGE',
'from "TEAM" x',
'where (:P34_SEARCH is null',
'        or upper(x."NAME") like ''%''||upper(:P34_SEARCH)||''%''',
'        or upper(x."CITY") like ''%''||upper(:P34_SEARCH)||''%''',
'    )',
'order by "NAME"'))
,p_ajax_enabled=>'Y'
